#nullable enable // autogenerated

using PVZEngine;

namespace MVZ2.Map
{
    public partial class MapElement
    {
        public T? GetProperty<T>(PropertyKey<T> name)
        {
            if (properties.TryGetProperty<T>(name, out var value))
            {
                return value;
            }
            if (Definition.TryGetProperty<T>(name, out var definitionValue))
            {
                return definitionValue;
            }
            var count = Definition.GetBehaviourCount();
            for (int i = 0; i < count; i++)
            {
                var behaviour = Definition.GetBehaviourAt(i);
                if (behaviour.TryGetProperty<T>(name, out var behaviourValue))
                {
                    return behaviourValue;
                }
            }
            return default;
        }

        public object? GetPropertyObject(IPropertyKey name)
        {
            if (properties.TryGetPropertyObject(name, out var value))
            {
                return value;
            }
            if (Definition.TryGetPropertyObject(name, out var definitionValue))
            {
                return definitionValue;
            }
            var count = Definition.GetBehaviourCount();
            for (int i = 0; i < count; i++)
            {
                var behaviour = Definition.GetBehaviourAt(i);
                if (behaviour.TryGetPropertyObject(name, out var behaviourValue))
                {
                    return behaviourValue;
                }
            }
            return default;
        }

        public void SetProperty<T>(PropertyKey<T> name, T? value)
        {
            properties.SetProperty<T>(name, value);
        }

        public void SetPropertyObject(IPropertyKey name, object? value)
        {
            properties.SetPropertyObject(name, value);
        }

        private PropertyDictionary properties = new PropertyDictionary();
    }
}
